-- ============================================================
-- TX 4a: core.articulo_impuesto — IGV18 por defecto en cada artículo activo
-- Equivale a SIGRE ARTICULO.flag_afecto_igv = '1' → tipo_impuesto1 = IGV18
-- Idempotente: no duplica si ya existe la pareja (articulo_id, tipos_impuesto_id)
-- ============================================================
BEGIN;

INSERT INTO core.articulo_impuesto (articulo_id, tipos_impuesto_id, orden)
SELECT a.id, ti.id, 1
FROM core.articulo a
JOIN core.tipos_impuesto ti ON ti.tipo_impuesto = 'IGV18'
WHERE a.flag_estado = '1'
ON CONFLICT (articulo_id, tipos_impuesto_id) DO NOTHING;

COMMIT;

