-- ============================================================
-- TX 8h: core.conversion_unidad (TON → SAC, factor 20)
-- ============================================================
WITH u AS (
    SELECT id, codigo FROM core.unidad_medida
)
INSERT INTO core.conversion_unidad (unidad_origen_id, unidad_destino_id, factor_conversion)
SELECT o.id, d.id, 20
FROM u o
CROSS JOIN u d
WHERE o.codigo = 'TON' AND d.codigo = 'SAC'
ON CONFLICT (unidad_origen_id, unidad_destino_id) DO NOTHING;

COMMIT;


