-- ============================================================
-- AUDITORIA: setear created_by/updated_by = 1 y fec_creacion = NOW()
-- en todos los registros sembrados que no tengan auditoria asignada.
-- Usuario 1 = ADMINISTRADOR SISTEMA
-- ============================================================
DO $$
DECLARE
    r RECORD;
    sql_upd TEXT;
    total INT := 0;
BEGIN
    FOR r IN
        SELECT schemaname, tablename
        FROM pg_tables
        WHERE schemaname IN ('auth','core','almacen','compras','ventas','finanzas','contabilidad','rrhh','activos','produccion','auditoria')
        ORDER BY schemaname, tablename
    LOOP
        IF EXISTS (
            SELECT 1 FROM information_schema.columns
            WHERE table_schema = r.schemaname AND table_name = r.tablename AND column_name = 'created_by'
        ) AND EXISTS (
            SELECT 1 FROM information_schema.columns
            WHERE table_schema = r.schemaname AND table_name = r.tablename AND column_name = 'fec_creacion'
        ) THEN
            IF EXISTS (
                SELECT 1 FROM information_schema.columns
                WHERE table_schema = r.schemaname AND table_name = r.tablename AND column_name = 'updated_by'
            ) THEN
                sql_upd := format(
                    'UPDATE %I.%I
                        SET created_by = COALESCE(created_by, 1),
                            fec_creacion = COALESCE(fec_creacion, NOW()),
                            updated_by = COALESCE(updated_by, 1)
                      WHERE created_by IS NULL OR fec_creacion IS NULL OR updated_by IS NULL',
                    r.schemaname, r.tablename
                );
            ELSE
                sql_upd := format(
                    'UPDATE %I.%I
                        SET created_by = COALESCE(created_by, 1),
                            fec_creacion = COALESCE(fec_creacion, NOW())
                      WHERE created_by IS NULL OR fec_creacion IS NULL',
                    r.schemaname, r.tablename
                );
            END IF;

            EXECUTE sql_upd;
            GET DIAGNOSTICS total = ROW_COUNT;
            IF total > 0 THEN
                RAISE NOTICE '[AUDIT] %.%: % registros actualizados', r.schemaname, r.tablename, total;
            END IF;
        END IF;
    END LOOP;
    RAISE NOTICE '[SEED] Carga inicial de maestros + ubigeo + auditoría completada.';
END $$;

