        SELECT id INTO v_matriz_id FROM contabilidad.matriz_contable WHERE codigo = v_rec.matriz_codigo LIMIT 1;
        IF v_matriz_id IS NOT NULL THEN
            INSERT INTO contabilidad.tipo_mov_matriz_subcat (tipo_mov, grp_cntbl, cod_sub_cat, item, matriz_contable_id)
            VALUES (v_rec.tipo_mov, v_rec.grp_cntbl, v_rec.cod_sub_cat, v_rec.item, v_matriz_id)
            ON CONFLICT (tipo_mov, grp_cntbl, cod_sub_cat, item) DO UPDATE SET matriz_contable_id = EXCLUDED.matriz_contable_id;
        END IF;
    END LOOP;
END $$;

