       correlativo_cheque, cod_moneda, saldo_disponible, sldo_contable, sldo_bancario,
       cod_origen, flag_replicacion_legacy, flag_uso_interno, flag_estado,
       nro_cci, flag_flujo_caja, nro_cuenta, flag_facturacion_simpl)
JOIN contabilidad.plan_contable_det pcd
  ON pcd.plan_contable_id = (SELECT pc.id FROM contabilidad.plan_contable pc WHERE pc.codigo = 'PCGE-2019')
 AND trim(both FROM pcd.cnta_ctbl::text) = trim(both FROM v.cnta_ctbl::text)
JOIN finanzas.banco b ON trim(b.cod_banco::text) = trim(v.cod_banco::text)
LEFT JOIN core.moneda m ON m.codigo = v.cod_moneda
LEFT JOIN auth.sucursal suc ON suc.codigo = v.cod_origen
ON CONFLICT (cod_ctabco) DO UPDATE SET
    plan_contable_det_id = EXCLUDED.plan_contable_det_id,
    banco_id           = EXCLUDED.banco_id,
    tipo_ctabco        = EXCLUDED.tipo_ctabco,
    descripcion        = EXCLUDED.descripcion,
    moneda_id          = EXCLUDED.moneda_id,
    saldo_disponible   = EXCLUDED.saldo_disponible,
    sucursal_id        = EXCLUDED.sucursal_id,
    flag_uso_interno   = EXCLUDED.flag_uso_interno,
    flag_estado        = EXCLUDED.flag_estado,
    nro_cci            = EXCLUDED.nro_cci,
    flag_flujo_caja    = EXCLUDED.flag_flujo_caja,
    flag_facturacion_simpl = EXCLUDED.flag_facturacion_simpl;

COMMIT;

